class Solution:
    def subdomainVisits(self, cpdomains):
        counts = {}
        for entry in cpdomains:
            space = entry.index(' ')
            rep = int(entry[:space])
            domain = entry[space + 1:]
            labels = domain.split('.')
            # Build every suffix explicitly and tally.
            for i in range(len(labels)):
                suffix = '.'.join(labels[i:])
                counts[suffix] = counts.get(suffix, 0) + rep
        return [str(v) + ' ' + k for k, v in counts.items()]

