var subdomainVisits = function(cpdomains) {
    const counts = new Map();
    for (const entry of cpdomains) {
        const sp = entry.indexOf(' ');
        const rep = parseInt(entry.slice(0, sp), 10);
        const parts = entry.slice(sp + 1).split('.');
        for (let i = 0; i < parts.length; i++) {
            const suffix = parts.slice(i).join('.');
            counts.set(suffix, (counts.get(suffix) || 0) + rep);
        }
    }
    const res = [];
    for (const [k, v] of counts) res.push(`${v} ${k}`);
    return res;
};
